                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const nextLine = currentLineIndex >= 0 && currentLineIndex < lyricsLines.length - 1
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ? (lyricsLines[currentLineIndex + 1]?.text ?? "") : "";

